package com.museumheist.game.world;import java.util.*;public class LevelManager {private final List<Level>levels=LevelFactory.createLevels();private int current;public int getLevelCount(){return levels.size();}public Level getCurrentLevel(){return levels.get(current);}public Level getLevel(int i){return levels.get(Math.max(0,Math.min(levels.size()-1,i)));}public int getCurrentLevelNumber(){return current+1;}public void setCurrentLevel(int i){current=Math.max(0,Math.min(levels.size()-1,i));}public boolean hasNextLevel(){return current+1<levels.size();}public void goToNextLevel(){if(hasNextLevel())current++;}public void restartCampaign(){current=0;}}
